            <div style={{ gridColumn: '2 / 4', display: 'flex', justifyContent: 'center', gap: '25px' }}>
                <div style={{ flex: 1, background: 'var(--bg-secondary)', padding: '20px', borderRadius: '15px', border: '1px solid rgba(255,255,255,0.05)' }}>
                    <h4 style={{ textAlign: 'center', color: 'var(--text-primary)', letterSpacing: '2px' }}>🏛️ CENTRAL ALPHA</h4>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                        {slots.filter(s => s.slotNumber.startsWith("CenterA-")).map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
                    </div>
                </div>
                <div style={{ width: '60px', background: 'rgba(0,0,0,0.3)', color: 'var(--text-secondary)', display: 'flex', alignItems: 'center', justifyContent: 'center', writingMode: 'vertical-rl', borderRadius: '10px', letterSpacing: '5px', fontSize: '0.9em', border: '1px dashed rgba(255,255,255,0.1)' }}>
                    ⇧ TRANSIT ⇩
                </div>
                <div style={{ flex: 1, background: 'var(--bg-secondary)', padding: '20px', borderRadius: '15px', border: '1px solid rgba(255,255,255,0.05)' }}>
                    <h4 style={{ textAlign: 'center', color: 'var(--text-primary)', letterSpacing: '2px' }}>🏛️ CENTRAL BETA</h4>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                        {slots.filter(s => s.slotNumber.startsWith("CenterB-")).map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
                    </div>
                </div>
            </div>

            {/* RIGHT COLUMN */}
            <div style={{ gridColumn: '4 / 5', background: 'var(--bg-secondary)', borderLeft: '2px solid var(--accent-orange)', padding: '20px', borderRadius: '15px' }}>
                <h4 style={{ textAlign: 'center', color: 'var(--accent-orange)', textShadow: '0 0 10px rgba(255,107,0,0.4)', letterSpacing: '2px' }}>📚 EAST WING</h4>
                <div style={{ display: 'flex', flexDirection: 'column', gap: '15px' }}>
                    {slots.filter(s => s.slotNumber.startsWith("Right-")).map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
                </div>
            </div>
        </div>
    );

    const StandardLayout = ({ slots, userBookingCount, book }) => (
        <div className="parking-layout" style={{ display: 'flex', flexDirection: 'column', gap: '25px' }}>
            {Object.entries(slots.reduce((groups, slot) => {
                const row = slot.slotNumber.split("-")[0];
                if (!groups[row]) groups[row] = [];
                groups[row].push(slot);
                return groups;
            }, {})).sort().map(([row, rowSlots]) => (
                <div key={row} className="parking-row" style={{ background: 'var(--glass-bg)', padding: '20px', borderRadius: '15px', border: '1px solid rgba(255,255,255,0.05)', boxShadow: '0 10px 20px rgba(0,0,0,0.3)' }}>
                    <div style={{ fontWeight: '800', marginBottom: '15px', color: 'var(--accent-cyan)', borderBottom: '1px solid rgba(0,240,255,0.2)', paddingBottom: '10px', letterSpacing: '2px' }}>ROW {row}</div>
                    <div className="slot-grid" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(80px, 1fr))', gap: '15px', marginBottom: '15px' }}>
                        {rowSlots.map(s => <SlotItem key={s._id} s={s} userBookingCount={userBookingCount} book={book} />)}
                    </div>
                    <div className="driving-lane" style={{ height: '40px', background: 'rgba(0,0,0,0.4)', borderRadius: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--text-secondary)', fontSize: '0.9em', letterSpacing: '5px', fontWeight: 'bold', border: '1px dashed rgba(255,255,255,0.1)' }}>⇦ TRANSIT LANE ⇨</div>
                </div>
            ))}
        </div>
    );

    // --- RENDER LOGIC ---
    const getLayout = () => {
        const name = parkingLot ? parkingLot.name : "";

        // Malls
        if (["City Center Mall", "Mega Hypermarket"].includes(name)) return <MallLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;

        // Tech & Commercial
        if (["Tech Park Plaza", "Downtown Commercial Complex", "Tech Startup Hub", "Science Museum"].includes(name)) return <TechLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;

        // Market / Food
        if (["Central Market Bazaar", "City Food Court", "Textile Bazaar Zone"].includes(name)) return <MarketLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;

        // Cinema / Events
        if (["Multiplex Cinema", "Convention Center"].includes(name)) return <CinemaLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;

        // Transit / Linear
        if (["Metro Station Parking"].includes(name)) return <TransitLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;

        // Nature / Park
        if (["Riverside Park"].includes(name)) return <NatureLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;

        // Fallback checks (existing)
        if (name.includes("Stadium")) return <StadiumLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;
        if (name.includes("Airport")) return <AirportLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;
        if (name.includes("Hospital")) return <HospitalLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;
        if (name.includes("Campus") || name.includes("University")) return <CampusLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;

        return <StandardLayout slots={slots} userBookingCount={userBookingCount} book={openBookingModal} />;
    };

    return (
        <div className="container">
            <h2>{parkingLot ? parkingLot.name : "Parking Slots"}</h2>
            {userBookingCount >= 2 && (
                <div style={{ color: "#d9534f", background: "#f2dede", padding: "10px", borderRadius: "4px", marginBottom: "15px", fontWeight: "bold", textAlign: "center", border: "1px solid #ebccd1" }}>
                    ⚠️ A user can book only 2 slots in a lot
                </div>
            )}

            {/* MODAL OVERLAY */}
            {showModal && (
                <div className="modal-overlay">
                    <div className="modal-content">
                        <h3 style={{ marginTop: 0, color: 'var(--text-primary)', borderBottom: '1px solid rgba(255,255,255,0.1)', paddingBottom: '15px', fontSize: '1.8rem', textAlign: 'center' }}>Secure Space 🚀</h3>

                        <label style={{ display: 'block', marginBottom: '15px' }}>
                            <span style={{ fontWeight: 'bold', display: 'block', marginBottom: '8px', color: 'var(--text-secondary)' }}>Vehicle Number:</span>
                            <input type="text"
                                value={bookingData.vehicleNumber}
                                onChange={e => {
                                    setBookingData({ ...bookingData, vehicleNumber: e.target.value.toUpperCase() });
                                    setValidationError(""); 
                                }}
                                placeholder="e.g. MH 12 AB 1234"
                            />
                            {validationError && <p style={{ color: 'var(--accent-pink)', fontSize: '0.9em', marginTop: '5px', textShadow: 'var(--shadow-neon-pink)' }}>{validationError}</p>}
                        </label>

                        <label style={{ display: 'block', marginBottom: '15px' }}>
                            <span style={{ fontWeight: 'bold', display: 'block', marginBottom: '8px', color: 'var(--text-secondary)' }}>Vehicle Type:</span>
                            <select
                                value={bookingData.vehicleType}
                                onChange={e => setBookingData({ ...bookingData, vehicleType: e.target.value })}
                            >
                                <option value="Four-wheeler">Four-wheeler 🚗</option>
                                <option value="Two-wheeler">Two-wheeler 🏍️</option>
                            </select>
                        </label>

                        <div style={{ marginBottom: '30px' }}>
                            <div style={{ fontWeight: 'bold', marginBottom: '10px', color: 'var(--text-secondary)' }}>From:</div>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px', marginBottom: '20px' }}>
                                <input type="date" value={bookingData.startDate} onChange={e => setBookingData({ ...bookingData, startDate: e.target.value })} />
                                <input type="time" value={bookingData.startTime} onChange={e => setBookingData({ ...bookingData, startTime: e.target.value })} />
                            </div>

                            <div style={{ fontWeight: 'bold', marginBottom: '10px', color: 'var(--text-secondary)' }}>To:</div>
                            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '15px' }}>
                                <input type="date" value={bookingData.endDate} onChange={e => setBookingData({ ...bookingData, endDate: e.target.value })} />
                                <input type="time" value={bookingData.endTime} onChange={e => setBookingData({ ...bookingData, endTime: e.target.value })} />
                            </div>
                        </div>

                        <div style={{ display: 'flex', gap: '15px', justifyContent: 'flex-end', marginTop: '20px' }}>
                            <button onClick={() => setShowModal(false)} style={{ padding: '12px 24px', background: 'transparent', color: 'var(--text-secondary)', border: '1px solid rgba(255,255,255,0.2)', borderRadius: 'var(--radius-lg)', cursor: 'pointer', fontWeight: 'bold', transition: 'var(--transition)' }}>Cancel</button>
                            <button onClick={handleConfirmBooking} className="btn-primary" style={{ width: 'auto' }}>Confirm Link</button>
                        </div>
                    </div>
                </div>
            )}

            {/* RENDER DYNAMIC LAYOUT */}
            <div className="parking-layout" style={{ marginTop: '20px' }}>
                {getLayout()}
            </div>
        </div>
    );
}
